joi_block.script:
triggered := false
if ((#DoorLock).doorLock_doorLockState == "closed") {
if (triggered == false) {
(#Light #Entrance).light_moveToBrightness(100, 0)
        delay(10 SEC)
(#Light #Entrance).light_moveToBrightness(0, 0)
        triggered = true
}
}
else {
triggered = false
}

